#include <stdio.h>

int main() {
    int T;
    scanf("%d", &T);

    while (T--) {
        int n;
        scanf("%d", &n);
        int a[n][n];
        int dp[n][n];

        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                scanf("%d", &a[i][j]);
                dp[i][j] = 0;
                if (i && j) {
                    dp[i][j] = (dp[i - 1][j] > dp[i][j - 1]) ? dp[i - 1][j] : dp[i][j - 1];
                } else if (i) {
                    dp[i][j] = dp[i - 1][j];
                } else if (j) {
                    dp[i][j] = dp[i][j - 1];
                }
                dp[i][j] += a[i][j];
            }
        }

        if (dp[n - 1][n - 1] < 0) {
            printf("Bad Judges\n");
        } else {
            printf("%.8lf\n", (double)dp[n - 1][n - 1] / (2 * n - 3));
        }
    }

    return 0;
}

