import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[][] a = new int[n][n];
            int[][] dp = new int[n][n];
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < n; j++) {
                    a[i][j] = sc.nextInt();
                    dp[i][j] = 0;
                    if (i > 0 && j > 0) {
                        dp[i][j] = Math.max(dp[i - 1][j], dp[i][j - 1]);
                    } else if (i > 0) {
                        dp[i][j] = dp[i - 1][j];
                    } else if (j > 0) {
                        dp[i][j] = dp[i][j - 1];
                    }
                    dp[i][j] += a[i][j];
                }
            }
            if (dp[n - 1][n - 1] < 0) {
                System.out.println("Bad Judges");
            } else {
                System.out.println(String.format("%.8f", (double) dp[n - 1][n - 1] / (2 * n - 3)));
            }
        }
    }
}

